import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define custom CUDA kernel for batched matrix multiplication with tiling optimization
bmm_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16

__global__ void batched_matmul_kernel(
    const float* A, 
    const float* B, 
    float* C,
    int batch_size,
    int m, int k, int n) {

    // Shared memory for tiles
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int batch = blockIdx.z;
    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    float sum = 0.0f;

    // Loop over tiles
    for (int t = 0; t < (k + TILE_SIZE - 1) / TILE_SIZE; ++t) {
        // Load tile from A
        int a_row = row;
        int a_col = t * TILE_SIZE + threadIdx.x;
        if (a_row < m && a_col < k) {
            As[threadIdx.y][threadIdx.x] = A[batch * m * k + a_row * k + a_col];
        } else {
            As[threadIdx.y][threadIdx.x] = 0.0f;
        }

        // Load tile from B
        int b_row = t * TILE_SIZE + threadIdx.y;
        int b_col = col;
        if (b_row < k && b_col < n) {
            Bs[threadIdx.y][threadIdx.x] = B[batch * k * n + b_row * n + b_col];
        } else {
            Bs[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        // Compute partial sum
        for (int i = 0; i < TILE_SIZE; ++i) {
            sum += As[threadIdx.y][i] * Bs[i][threadIdx.x];
        }

        __syncthreads();
    }

    // Write result
    if (row < m && col < n) {
        C[batch * m * n + row * n + col] = sum;
    }
}

torch::Tensor batched_matmul_cuda(torch::Tensor A, torch::Tensor B) {
    auto sizes_a = A.sizes();
    auto sizes_b = B.sizes();

    int batch_size = sizes_a[0];
    int m = sizes_a[1];
    int k = sizes_a[2];
    int n = sizes_b[2];

    auto C = torch::zeros({batch_size, m, n}, A.options());

    // Configure grid and block dimensions
    dim3 block_dim(TILE_SIZE, TILE_SIZE, 1);
    dim3 grid_dim(
        (n + TILE_SIZE - 1) / TILE_SIZE,
        (m + TILE_SIZE - 1) / TILE_SIZE,
        batch_size
    );

    // Launch kernel
    batched_matmul_kernel<<<grid_dim, block_dim>>>(
        A.data_ptr<float>(),
        B.data_ptr<float>(),
        C.data_ptr<float>(),
        batch_size,
        m, k, n
    );

    return C;
}
"""

bmm_cpp_source = "torch::Tensor batched_matmul_cuda(torch::Tensor A, torch::Tensor B);"

# Compile the inline CUDA code
batched_matmul = load_inline(
    name="batched_matmul",
    cpp_sources=bmm_cpp_source,
    cuda_sources=bmm_source,
    functions=["batched_matmul_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    """
    Performs optimized batched matrix multiplication using custom CUDA kernel.
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.batched_matmul = batched_matmul

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        """
        Performs batched matrix multiplication using custom CUDA kernel.

        Args:
            A: Input tensor of shape (batch_size, m, k).
            B: Input tensor of shape (batch_size, k, n).

        Returns:
            C: Output tensor of shape (batch_size, m, n).
        """
        return self.batched_matmul.batched_matmul_cuda(A, B)

